1	`timescale 1ns / 1ps
2	// ============================================================================
3	// xfft_16.v — 16-point FFT with AXI-Stream interface
4	// ============================================================================
5	// Wraps the synthesizable fft_engine (radix-2 DIT) with the AXI-Stream port
6	// interface expected by the doppler_processor dual-FFT architecture.
7	//
8	// Used by the doppler_processor dual-FFT architecture (2 x 16-pt sub-frames).
9	//
10	// Data format: {Q[15:0], I[15:0]} packed 32-bit.
11	// Config tdata[0]: 1 = forward FFT, 0 = inverse FFT.
12	// ============================================================================
13	
14	module xfft_16 (
15	    input  wire        aclk,
16	    input  wire        aresetn,
17	
18	    // Configuration channel (AXI-Stream slave)
19	    input  wire [7:0]  s_axis_config_tdata,
20	    input  wire        s_axis_config_tvalid,
21	    output wire        s_axis_config_tready,
22	
23	    // Data input channel (AXI-Stream slave)
24	    input  wire [31:0] s_axis_data_tdata,
25	    input  wire        s_axis_data_tvalid,
26	    input  wire        s_axis_data_tlast,
27	
28	    // Data output channel (AXI-Stream master)
29	    output wire [31:0] m_axis_data_tdata,
30	    output wire        m_axis_data_tvalid,
31	    output wire        m_axis_data_tlast,
32	    input  wire        m_axis_data_tready
33	);
34	
35	// ============================================================================
36	// PARAMETERS
37	// ============================================================================
38	localparam N     = 16;
39	localparam LOG2N = 4;
40	
41	// ============================================================================
42	// INTERNAL SIGNALS
43	// ============================================================================
44	
45	// FSM states
46	localparam [2:0] S_IDLE    = 3'd0,
47	                 S_CONFIG  = 3'd1,
48	                 S_FEED    = 3'd2,
49	                 S_WAIT    = 3'd3,
50	                 S_OUTPUT  = 3'd4;
51	
52	reg [2:0] state;
53	
54	// Configuration
55	reg inverse_reg;
56	
57	// Input buffering
58	reg signed [15:0] in_buf_re [0:N-1];
59	reg signed [15:0] in_buf_im [0:N-1];
60	reg [4:0] in_count;
61	
62	// Output buffering
63	reg signed [15:0] out_buf_re [0:N-1];
64	reg signed [15:0] out_buf_im [0:N-1];
65	reg [4:0] out_count;
66	reg [4:0] out_total;
67	
68	// FFT engine interface
69	reg fft_start;
70	reg fft_inverse;
71	reg signed [15:0] fft_din_re, fft_din_im;
72	reg fft_din_valid;
73	wire signed [15:0] fft_dout_re, fft_dout_im;
74	wire fft_dout_valid;
75	wire fft_busy;
76	wire fft_done;
77	
78	// Feed counter
79	reg [4:0] feed_count;
80	
81	// ============================================================================
82	// FFT ENGINE INSTANCE
83	// ============================================================================
84	fft_engine #(
85	    .N(N),
86	    .LOG2N(LOG2N),
87	    .DATA_W(16),
88	    .INTERNAL_W(32),
89	    .TWIDDLE_W(16),
90	    .TWIDDLE_FILE("fft_twiddle_16.mem")
91	) fft_core (
92	    .clk(aclk),
93	    .reset_n(aresetn),
94	    .start(fft_start),
95	    .inverse(fft_inverse),
96	    .din_re(fft_din_re),
97	    .din_im(fft_din_im),
98	    .din_valid(fft_din_valid),
99	    .dout_re(fft_dout_re),
100	    .dout_im(fft_dout_im),
101	    .dout_valid(fft_dout_valid),
102	    .busy(fft_busy),
103	    .done(fft_done)
104	);
105	
106	// ============================================================================
107	// AXI-STREAM OUTPUTS
108	// ============================================================================
109	assign s_axis_config_tready = (state == S_IDLE);
110	assign m_axis_data_tdata  = {out_buf_im[out_count[3:0]], out_buf_re[out_count[3:0]]};
111	assign m_axis_data_tvalid = (state == S_OUTPUT) && (out_count < N);
112	assign m_axis_data_tlast  = (state == S_OUTPUT) && (out_count == N - 1);
113	
114	// ============================================================================
115	// BUFFER WRITE LOGIC — separate always block, NO async reset
116	// ============================================================================
117	reg in_buf_we;
118	reg [3:0] in_buf_waddr;
119	reg signed [15:0] in_buf_wdata_re, in_buf_wdata_im;
120	
121	reg out_buf_we;
122	reg [3:0] out_buf_waddr;
123	reg signed [15:0] out_buf_wdata_re, out_buf_wdata_im;
124	
125	always @(posedge aclk) begin
126	    if (in_buf_we) begin
127	        in_buf_re[in_buf_waddr] <= in_buf_wdata_re;
128	        in_buf_im[in_buf_waddr] <= in_buf_wdata_im;
129	    end
130	    if (out_buf_we) begin
131	        out_buf_re[out_buf_waddr] <= out_buf_wdata_re;
132	        out_buf_im[out_buf_waddr] <= out_buf_wdata_im;
133	    end
134	end
135	
136	// ============================================================================
137	// MAIN FSM
138	// ============================================================================
139	always @(posedge aclk or negedge aresetn) begin
140	    if (!aresetn) begin
141	        state        <= S_IDLE;
142	        inverse_reg  <= 1'b0;
143	        in_count     <= 0;
144	        out_count    <= 0;
145	        out_total    <= 0;
146	        feed_count   <= 0;
147	        fft_start    <= 1'b0;
148	        fft_inverse  <= 1'b0;
149	        fft_din_re   <= 0;
150	        fft_din_im   <= 0;
151	        fft_din_valid <= 1'b0;
152	        in_buf_we    <= 1'b0;
153	        in_buf_waddr <= 0;
154	        in_buf_wdata_re <= 0;
155	        in_buf_wdata_im <= 0;
156	        out_buf_we   <= 1'b0;
157	        out_buf_waddr <= 0;
158	        out_buf_wdata_re <= 0;
159	        out_buf_wdata_im <= 0;
160	    end else begin
161	        fft_start     <= 1'b0;
162	        fft_din_valid <= 1'b0;
163	        in_buf_we     <= 1'b0;
164	        out_buf_we    <= 1'b0;
165	
166	        case (state)
167	
168	        S_IDLE: begin
169	            in_count <= 0;
170	            if (s_axis_config_tvalid) begin
171	                inverse_reg <= ~s_axis_config_tdata[0];
172	                state       <= S_FEED;
173	                in_count    <= 0;
174	                feed_count  <= 0;
175	            end
176	        end
177	
178	        S_FEED: begin
179	            if (in_count < N) begin
