181	                    in_buf_we       <= 1'b1;
182	                    in_buf_waddr    <= in_count[3:0];
183	                    in_buf_wdata_re <= s_axis_data_tdata[15:0];
184	                    in_buf_wdata_im <= s_axis_data_tdata[31:16];
185	                    in_count <= in_count + 1;
186	                end
187	            end else if (feed_count == 0) begin
188	                fft_start   <= 1'b1;
189	                fft_inverse <= inverse_reg;
190	                feed_count  <= 0;
191	                state       <= S_WAIT;
192	                out_total   <= 0;
193	            end
194	        end
195	
196	        S_WAIT: begin
197	            if (feed_count < N) begin
198	                fft_din_re   <= in_buf_re[feed_count[3:0]];
