wire [16:0] cfar_detect_threshold;
wire [15:0] cfar_detect_count;
wire        cfar_busy_w;
wire [7:0]  cfar_status_w;

cfar_ca cfar_inst (
    .clk(clk_100m_buf),
    .reset_n(sys_reset_n),

    // Doppler processor outputs (DC-notch filtered)
    .doppler_data(notched_doppler_data),
