    .range_bin_in(notched_range_bin),
    .frame_complete(rx_frame_complete),

    // Configuration
    .cfg_guard_cells(host_cfar_guard),
    .cfg_train_cells(host_cfar_train),
    .cfg_alpha(host_cfar_alpha),
